Refactor this React Native component. It currently handles API fetching, business logic (discount calculation, stock validation), and UI rendering all in one file. Break it into clean, maintainable pieces.

```typescript
// ProductDetailScreen.tsx
import React, { useState, useEffect } from 'react';
import { View, Text, TouchableOpacity, ActivityIndicator, Alert, ScrollView } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const ProductDetailScreen = ({ route, navigation }) => {
  const { productId } = route.params;
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [cartCount, setCartCount] = useState(0);
  const [userType, setUserType] = useState('regular');

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch(`https://api.example.com/products/${productId}`);
        const data = await response.json();
        setProduct(data);
        const user = await AsyncStorage.getItem('user');
        if (user) {
          const parsed = JSON.parse(user);
          setUserType(parsed.type);
        }
        const cart = await AsyncStorage.getItem('cart');
        if (cart) {
          const items = JSON.parse(cart);
          setCartCount(items.length);
        }
      } catch (error) {
        Alert.alert('Error', 'Failed to load product');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [productId]);

  const calculatePrice = () => {
    if (!product) return 0;
    let price = product.price;
    if (userType === 'premium') {
      price = price * 0.9;
    } else if (userType === 'vip') {
      price = price * 0.8;
    }
    if (product.stock < 5) {
      price = price * 1.1; // scarcity markup
    }
    if (cartCount > 3) {
      price = price * 0.95; // bulk discount
    }
    return Math.round(price * 100) / 100;
  };

  const addToCart = async () => {
    if (!product) return;
    if (product.stock <= 0) {
      Alert.alert('Out of Stock', 'This product is currently unavailable');
      return;
    }
    try {
      const cart = await AsyncStorage.getItem('cart');
      const items = cart ? JSON.parse(cart) : [];
      items.push({ id: product.id, name: product.name, price: calculatePrice(), quantity: 1 });
      await AsyncStorage.setItem('cart', JSON.stringify(items));
      setCartCount(items.length);
      Alert.alert('Success', 'Added to cart!');
    } catch (error) {
      Alert.alert('Error', 'Failed to add to cart');
    }
  };

  if (loading) return <ActivityIndicator size="large" />;
  if (!product) return <Text>Product not found</Text>;

  return (
    <ScrollView style={{ flex: 1, padding: 16 }}>
      <Text style={{ fontSize: 24, fontWeight: 'bold' }}>{product.name}</Text>
      <Text style={{ fontSize: 16, color: '#666', marginTop: 8 }}>{product.description}</Text>
      <Text style={{ fontSize: 20, color: '#e74c3c', marginTop: 16 }}>${calculatePrice()}</Text>
      {product.stock < 5 && product.stock > 0 && (
        <Text style={{ color: '#e67e22', marginTop: 4 }}>Only {product.stock} left!</Text>
      )}
      {product.stock <= 0 && (
        <Text style={{ color: '#e74c3c', marginTop: 4 }}>Out of Stock</Text>
      )}
      <TouchableOpacity
        onPress={addToCart}
        disabled={product.stock <= 0}
        style={{ backgroundColor: product.stock > 0 ? '#2ecc71' : '#95a5a6', padding: 16, borderRadius: 8, marginTop: 24, alignItems: 'center' }}
      >
        <Text style={{ color: '#fff', fontSize: 18, fontWeight: 'bold' }}>Add to Cart ({cartCount})</Text>
      </TouchableOpacity>
    </ScrollView>
  );
};

export default ProductDetailScreen;
