// orderUtils.ts
export interface OrderItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
  discount?: number;
}

export interface OrderSummary {
  items: OrderItem[];
  subtotal: number;
  tax: number;
  total: number;
  formattedTotal: string;
}

// This function has a bug with quantity calculation
export const formatOrderSummary = (items: OrderItem[], taxRate: number = 0.1): OrderSummary => {
  const subtotal = items.reduce((sum, item) => {
    const itemDiscount = item.discount || 0;
    const itemPrice = item.price - itemDiscount;
    return sum + itemPrice; // BUG: not multiplying by quantity
  }, 0);

  const tax = subtotal * taxRate;
  const total = subtotal + tax;

  return {
    items,
    subtotal,
    tax,
    total,
    formattedTotal: `$${total.toFixed(2)}`,
  };
};

